def ValidateInputType(input: Any) -> Tuple[str, Optional[str]]:
    """
    Validate that the input is a string. If not, attempt to convert it to a string.
    Returns a tuple of (validated_input, validation_error).
    """
    if isinstance(input, str):
        return input, None
    try:
        converted = str(input)
        return converted, None
    except Exception:
        return "", "Input is not a string and cannot be converted"

def ParseJsonInput(input: Any) -> Tuple[Optional[dict], Optional[str]]:
    validated_input, validation_error = ValidateInputType(input)
    if validation_error is not None:
        return None, validation_error
    parsed_data, parse_error = ParseJsonString(validated_input)
    return parsed_data, parse_error

def CheckParsedData(parsed_data: Optional[dict]) -> Tuple[Optional[dict], Optional[str]]:
    if parsed_data is None:
        return None, 'Invalid input: parsed data is None'
    return parsed_data, None

def ExtractCommand(valid_data: Optional[dict]) -> Tuple[Optional[str], Optional[str]]:
    if 'command' not in valid_data:
        return None, 'Missing command field'
    return valid_data['command'], None

def ValidateCommand(command_value: Optional[str]) -> Tuple[Optional[str], Optional[str]]:
    allowed_commands = ['create', 'list', 'complete', 'delete']
    if command_value in allowed_commands:
        return command_value, None
    else:
        return None, f'Unknown command: {command_value}'

def CheckTaskDataPresence(parsed_data: Optional[dict]) -> bool:
    if parsed_data is None:
        return False
    return 'task_data' in parsed_data

def ExtractTaskDataValue(parsed_data: Optional[dict], has_task_data: bool) -> Optional[dict]:
    if has_task_data and parsed_data is not None and 'task_data' in parsed_data:
        return parsed_data['task_data']
    return None

def CombineParseResults(parse_error: Optional[str], command: Optional[str], validation_error: Optional[str], task_data: Optional[dict]) -> Tuple[Optional[str], Optional[dict], Optional[str]]:
    # Check parse_error first; if present, return None for command and task_data with parse_error
    if parse_error is not None:
        return None, None, parse_error
    # Else check validation_error; if present, return None for command and task_data with validation_error
    if validation_error is not None:
        return None, None, validation_error
    # Else return command, task_data, and None error
    return command, task_data, None

def FormatCreateTaskResult(new_task: dict) -> dict:
    result = {
        'success': True,
        'message': 'Task created successfully',
        'task': new_task
    }
    return result

def UpdateTaskStatus(found_task: Optional[dict], task_index: int, tasks: list) -> Tuple[Optional[dict], list]:
    if found_task is not None:
        updated_task = found_task.copy()
        updated_task['status'] = 'completed'
        tasks[task_index] = updated_task
        return updated_task, tasks
    else:
        return None, tasks

def CompleteTask(task_data: dict, tasks: list) -> Tuple[dict, list]:
    task_id = task_data.get('id')
    found_task, task_index = FindTaskById(task_id, tasks)
    updated_task, updated_tasks = UpdateTaskStatus(found_task, task_index, tasks)
    if updated_task is not None:
        result = {'success': True, 'message': 'Task completed successfully', 'task': updated_task}
    else:
        result = {'success': False, 'message': 'Task not found', 'task': None}
    return result, updated_tasks

def BuildResult(deleted_task: dict, task_id: int) -> dict:
    result = {
        'success': True,
        'message': f'Task {task_id} deleted successfully',
        'deleted_task': deleted_task
    }
    return result

def ExecuteCommand(command: str, task_data: Optional[dict]) -> dict:
    # Access global data stores
    global tasks, next_id

    # Route to appropriate child function based on command
    if command == 'create':
        return CreateTask(task_data, tasks, next_id)
    elif command == 'list':
        return ListTasks(task_data, tasks)
    elif command == 'complete':
        return CompleteTask(task_data, tasks)
    elif command == 'delete':
        return DeleteTask(task_data, tasks)
    else:
        return {'success': False, 'message': f'Unknown command: {command}', 'data': None}

def HandleParseError(parse_error: Optional[str]) -> Optional[dict]:
    if parse_error is not None:
        return {'success': False, 'message': parse_error}
    return None

def FormatResponse(result: dict, parse_error: Optional[str]) -> Any:
    error_json = HandleParseError(parse_error)
    return FormatSuccessResponse(result, error_json)

